// src/firebase/posts.js
import {
  collection,
  addDoc,
  getDocs,
  getDoc,
  doc,
  deleteDoc,
  updateDoc,
  query,
  orderBy,
  onSnapshot,
  serverTimestamp,
  where,
} from "firebase/firestore";
import {
  ref,
  uploadBytesResumable,
  getDownloadURL,
  deleteObject,
} from "firebase/storage";
import { db, storage } from "./config";

const POSTS_COLLECTION = "posts";

// ── Upload image to Firebase Storage ──
export const uploadImage = (file, onProgress) => {
  return new Promise((resolve, reject) => {
    const storageRef = ref(storage, `blog-images/${Date.now()}_${file.name}`);
    const uploadTask = uploadBytesResumable(storageRef, file);

    uploadTask.on(
      "state_changed",
      (snapshot) => {
        const pct = Math.round(
          (snapshot.bytesTransferred / snapshot.totalBytes) * 100
        );
        if (onProgress) onProgress(pct);
      },
      (error) => reject(error),
      async () => {
        const url = await getDownloadURL(uploadTask.snapshot.ref);
        resolve({ url, path: storageRef.fullPath });
      }
    );
  });
};

// ── Delete image from Storage ──
export const deleteImage = async (imagePath) => {
  if (!imagePath) return;
  try {
    const imageRef = ref(storage, imagePath);
    await deleteObject(imageRef);
  } catch (e) {
    console.warn("Image delete failed:", e.message);
  }
};

// ── Create post ──
export const createPost = async (postData) => {
  const docRef = await addDoc(collection(db, POSTS_COLLECTION), {
    ...postData,
    createdAt: serverTimestamp(),
    updatedAt: serverTimestamp(),
    likes: 0,
    views: 0,
  });
  return docRef.id;
};

// ── Real-time posts listener ──
export const subscribeToPosts = (callback) => {
  const q = query(
    collection(db, POSTS_COLLECTION),
    orderBy("createdAt", "desc")
  );
  return onSnapshot(q, (snapshot) => {
    const posts = snapshot.docs.map((doc) => ({
      id: doc.id,
      ...doc.data(),
    }));
    callback(posts);
  });
};

// ── Get single post ──
export const getPost = async (id) => {
  const docRef = doc(db, POSTS_COLLECTION, id);
  const docSnap = await getDoc(docRef);
  if (docSnap.exists()) return { id: docSnap.id, ...docSnap.data() };
  return null;
};

// ── Update post ──
export const updatePost = async (id, data) => {
  const docRef = doc(db, POSTS_COLLECTION, id);
  await updateDoc(docRef, { ...data, updatedAt: serverTimestamp() });
};

// ── Delete post ──
export const deletePost = async (id, imagePath) => {
  await deleteDoc(doc(db, POSTS_COLLECTION, id));
  if (imagePath) await deleteImage(imagePath);
};

// ── Like a post ──
export const likePost = async (id, currentLikes) => {
  const docRef = doc(db, POSTS_COLLECTION, id);
  await updateDoc(docRef, { likes: currentLikes + 1 });
};

// ── Get posts by category ──
export const getPostsByCategory = async (category) => {
  const q = query(
    collection(db, POSTS_COLLECTION),
    where("category", "==", category),
    orderBy("createdAt", "desc")
  );
  const snap = await getDocs(q);
  return snap.docs.map((doc) => ({ id: doc.id, ...doc.data() }));
};
